// Validate input — handle both new project and retry
const body = $input.first().json.body || $input.first().json;
let niche = body.niche?.trim();
const projectId = body.project_id;

// If retrying (project_id but no niche), fetch niche from existing project
if (!niche && projectId) {
  const SB = $env.SUPABASE_URL;
  const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
  const resp = await fetch(SB + '/rest/v1/projects?id=eq.' + projectId + '&select=niche,niche_description', {
    headers: { 'apikey': SRK, 'Authorization': 'Bearer ' + SRK }
  });
  const text = await resp.text();
  try {
    const rows = JSON.parse(text);
    if (rows?.[0]?.niche) {
      niche = rows[0].niche;
    }
  } catch (e) {}
}

if (!niche || niche.length < 2) {
  throw new Error('Niche name is required (min 2 characters)');
}

return [{
  json: {
    niche,
    description: body.description?.trim() || body.niche_description?.trim() || '',
    target_video_count: parseInt(body.target_video_count, 10) || 25,
    channel_style: body.channel_style || '2hr_documentary',
    reference_analyses: Array.isArray(body.reference_analyses) ? body.reference_analyses : [],
    project_id: projectId || null
  }
}];

// Extract project from Supabase response (returns array)
const response = $input.first().json;
const project = Array.isArray(response) ? response[0] : response;
if (!project?.id) {
  throw new Error('Failed to create project — no ID returned');
}
// Pass reference_analyses from upstream
const upstream = $('Validate Input').first().json;
return [{ json: { project_id: project.id, niche: project.niche, description: project.niche_description || '', reference_analyses: upstream.reference_analyses || [] } }];

// Idempotency check: does a niche_profile already exist for this project?
const response = $input.first().json;
const profiles = Array.isArray(response) ? response : [];
const skip_research = profiles.length > 0;

// Pass through project_id and niche from upstream Extract Project ID node
const projectData = $('Extract Project ID').first().json;

return [{ json: {
  project_id: projectData.project_id,
  niche: projectData.niche,
  description: projectData.description,
  skip_research
} }];

// Detect if Claude research returned an error response
const response = $input.first().json;

if (response.error || response.type === 'error') {
  const errorMsg = response.error?.message || JSON.stringify(response.error || response);
  return [{ json: {
    isError: true,
    error_message: 'Anthropic API error during research: ' + errorMsg,
    project_id: $('Extract Project ID').first().json.project_id,
    niche: $('Extract Project ID').first().json.niche,
    description: $('Extract Project ID').first().json.description,
    skip_research: false
  }}];
}

// Success — pass through response
return [{ json: { ...response, isError: false } }];

// Parse Claude's niche research response
const response = $input.first().json;

// Extract text content from response
const textBlocks = (response.content || []).filter(c => c.type === 'text');
const rawText = textBlocks.map(c => c.text).join('');

// Strip markdown code fences if present
let jsonText = rawText.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();

// Find the JSON object
const jsonStart = jsonText.indexOf('{');
const jsonEnd = jsonText.lastIndexOf('}');
if (jsonStart === -1 || jsonEnd === -1) {
  throw new Error('No JSON found in Claude response');
}
jsonText = jsonText.substring(jsonStart, jsonEnd + 1);

let research;
try {
  research = JSON.parse(jsonText);
} catch (e) {
  throw new Error(`Failed to parse research JSON: ${e.message}`);
}

// Pass through project context + parsed research
return [{
  json: {
    project_id: $('Extract Project ID').first().json.project_id,
    niche: $('Extract Project ID').first().json.niche,
    description: $('Extract Project ID').first().json.description,
    research,
    competitor_analysis: research.competitor_analysis || {},
    audience_pain_points: research.audience_pain_points || {},
    keyword_research: research.keyword_research || {},
    blue_ocean_opportunities: research.blue_ocean_opportunities || {},
    expertise_profile: research.expertise_profile || '',
    system_prompt: research.system_prompt || '',
    playlist_angles: research.playlist_angles || [],
    red_ocean_topics: research.red_ocean_topics || [],
    audience_psychographic: research.audience_psychographic || ''
  }
}];

// Compute next version number for prompt_configs
const versions = $('Get Prompt Version').first().json;
const versionArray = Array.isArray(versions) ? versions : [];
const maxVersion = versionArray.length > 0 ? (versionArray[0].version || 1) : 1;
const next_version = maxVersion + 1;

const projectData = $('Idempotency Check').first().json;

return [{ json: {
  project_id: projectData.project_id,
  niche: projectData.niche,
  description: projectData.description,
  next_version
} }];

// Merge project data for re-triggered prompt generation
const projectArr = $input.first().json;
const project = Array.isArray(projectArr) ? projectArr[0] : projectArr;

const versionData = $('Compute Next Version').first().json;

return [{ json: {
  project_id: versionData.project_id,
  niche: project.niche || versionData.niche,
  expertise_profile: project.niche_expertise_profile || '',
  system_prompt: project.niche_system_prompt || '',
  playlist_angles: [
    { name: project.playlist1_name || 'Playlist 1', theme: project.playlist1_theme || '' },
    { name: project.playlist2_name || 'Playlist 2', theme: project.playlist2_theme || '' },
    { name: project.playlist3_name || 'Playlist 3', theme: project.playlist3_theme || '' }
  ],
  red_ocean_topics: project.niche_red_ocean_topics || [],
  audience_psychographic: '',
  blue_ocean_opportunities: { positioning_statement: project.niche_blue_ocean_strategy || '' },
  next_version: versionData.next_version,
  is_retrigger: true
} }];

// Detect if Claude prompts generation returned an error or truncated response
const response = $input.first().json;

if (response.error || response.type === 'error') {
  const errorMsg = response.error?.message || JSON.stringify(response.error || response);
  return [{ json: {
    isError: true,
    error_message: 'Anthropic API error during prompt generation: ' + errorMsg,
    project_id: $('Extract Project ID').first().json.project_id
  }}];
}

// Check for truncated response (max_tokens hit)
if (response.stop_reason === 'max_tokens') {
  return [{ json: {
    isError: true,
    error_message: 'Claude response truncated (stop_reason=max_tokens, output_tokens=' + (response.usage?.output_tokens || 'unknown') + '). Prompt templates too long — reduce verbosity.',
    project_id: $('Extract Project ID').first().json.project_id
  }}];
}

// Success — pass through
return [{ json: { ...response, isError: false } }];

// Parse Claude's prompt generation response
const response = $input.first().json;

if (response.error) {
  throw new Error('Anthropic API error: ' + (response.error.message || JSON.stringify(response.error)));
}

const textBlocks = (response.content || []).filter(c => c.type === 'text');
const rawText = textBlocks.map(c => c.text).join('');

// Strip markdown fences
let jsonText = rawText.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
const jsonStart = jsonText.indexOf('[');
const jsonEnd = jsonText.lastIndexOf(']');
if (jsonStart === -1 || jsonEnd === -1) {
  throw new Error('No JSON array found in prompt generation response');
}
jsonText = jsonText.substring(jsonStart, jsonEnd + 1);

let prompts;
try {
  prompts = JSON.parse(jsonText);
} catch (e) {
  throw new Error('Failed to parse prompts JSON: ' + e.message);
}

if (!Array.isArray(prompts) || prompts.length < 2) {
  throw new Error('Expected 2 prompts, got ' + (prompts?.length || 0));
}

// Verify we have visual_director and scene_segmenter
const requiredTypes = ['visual_director', 'scene_segmenter'];
const receivedTypes = prompts.map(p => p.prompt_type);
const missingTypes = requiredTypes.filter(t => !receivedTypes.includes(t));
if (missingTypes.length > 0) {
  throw new Error('Missing required prompt types: ' + missingTypes.join(', '));
}

const project_id = $('Extract Project ID').first().json.project_id;

// Determine version: use next_version if re-trigger, else 1
let version = 1;
try {
  const mergeData = $('Merge Re-trigger Data').first().json;
  if (mergeData && mergeData.next_version) {
    version = mergeData.next_version;
  }
} catch(e) {
  // Not a re-trigger — version stays 1
}

// Build prompt_configs rows
const rows = prompts.map(p => ({
  project_id,
  prompt_type: p.prompt_type,
  prompt_text: p.prompt_text,
  version,
  is_active: true
}));

return [{ json: { project_id, prompt_configs: rows } }];

const d = $json;
const niche = d.niche || '';
const ep = d.expertise_profile || '';
const sp = d.system_prompt || '';

const prompt = 'You are generating dynamic prompt templates for an AI video production platform. The niche is "' + niche + '".

Niche expertise profile: ' + ep + '
Niche system prompt (abbreviated): ' + sp.substring(0, 500) + '

Generate 2 prompt templates as JSON. Each prompt must use {{variable}} placeholders.

The 2 prompts are:

1. visual_director - Assigns visual composition and image prompts to scenes. ALL scenes are static_image (no i2v/t2v). Focus on composition, lighting, mood, and style. Keep concise.

2. scene_segmenter - Splits script into ~170 scenes with narration, image_prompt, visual_type (always "static_image"), emotional_beat, chapter. Keep concise.

Return ONLY valid JSON (no markdown) as an array:
[{ "prompt_type": "visual_director", "prompt_text": "..." }, { "prompt_type": "scene_segmenter", "prompt_text": "..." }]

Concise prompts only. Under 400 words each.';

const body = { model: 'claude-sonnet-4-20250514', max_tokens: 4096, messages: [{ role: 'user', content: prompt }] };

return [{ json: { ...d, anthropicBody: JSON.stringify(body) } }];

// Wait 90 seconds to avoid Anthropic 429 rate limit after heavy research call
await new Promise(resolve => setTimeout(resolve, 90000));
return items;

const data = $input.first().json;
// Pull niche + project_id from upstream nodes since HTTP nodes with return=minimal lose context
const validateData = $('Validate Input').first().json;
const projectId = validateData.project_id || $('Extract Project ID').first().json.project_id;
const niche = validateData.niche;
const description = validateData.description || '';
const analysisIds = validateData.reference_analyses || $('Extract Project ID').first().json.reference_analyses || [];
let analysisContext = '';
const fullAnalyses = [];

if (analysisIds.length > 0) {
  const SB = $env.SUPABASE_URL;
  const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;

  for (const aid of analysisIds.slice(0, 5)) {
    try {
      const resp = await fetch(SB + '/rest/v1/yt_video_analyses?id=eq.' + aid + '&select=video_title,channel_name,niche_category,views,likes,comments,duration_seconds,analysis', {
        headers: { 'apikey': SRK, 'Authorization': 'Bearer ' + SRK }
      });
      const rows = await resp.json();
      const a = rows?.[0];
      if (!a?.analysis) continue;

      fullAnalyses.push({
        video_title: a.video_title,
        channel_name: a.channel_name,
        niche_category: a.niche_category,
        views: a.views,
        likes: a.likes,
        comments: a.comments,
        duration_seconds: a.duration_seconds,
        ...a.analysis
      });

      const an = a.analysis;
      const sections = [];
      sections.push('Reference Video: "' + (a.video_title || '') + '" (' + (a.views || 0).toLocaleString() + ' views)');
      if (an.one_line_summary) sections.push('Summary: ' + an.one_line_summary);
      if (an.weaknesses?.length) sections.push('Weaknesses: ' + an.weaknesses.join('; '));
      if (an.ten_x_strategy?.recommended_angle) sections.push('Angle: ' + an.ten_x_strategy.recommended_angle);
      analysisContext += '\n\n--- ANALYSIS ---\n' + sections.join('\n');
    } catch (e) { /* skip */ }
  }

  if (fullAnalyses.length > 0) {
    try {
      const SB = $env.SUPABASE_URL;
      const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
      await fetch(SB + '/rest/v1/projects?id=eq.' + projectId, {
        method: 'PATCH',
        headers: {
          'apikey': SRK, 'Authorization': 'Bearer ' + SRK,
          'Content-Type': 'application/json', 'Prefer': 'return=minimal'
        },
        body: JSON.stringify({ competitive_analysis: { analyses: fullAnalyses } })
      });
    } catch (e) { /* non-fatal */ }
  }
}

const enrichedDescription = description + analysisContext;
return [{ json: { niche, description: enrichedDescription, project_id: projectId, analysis_context: analysisContext, has_analysis: analysisContext.length > 0, reference_analyses: analysisIds } }];
